		gameWS.onmessage=function(k){
		
		var tmpMess=k.data.split("#");
		
			if(tmpMess[0]=='UPDATE' && gameController.win<=0 && gameController.fuq.cfg!=undefined){
			
			if(gameController.qgi!=parseInt(tmpMess[1])){
				
			gameController.qgi=parseInt(tmpMess[1]);	
			
			gameController.fuq.cfg.foo("creditd", "#eug", [gameController.gah(tmpMess[1]), true]);	
				
			}
			
			
			
			}	
			
		}
		
